import React, { Component } from 'react';

class Membro extends Component {
    constructor(props) {
        super(props);
        this.state = {
            nome: "Visitante",
            status: true
        };
        this.entrar = this.entrar.bind(this);
    }

    entrar(name) {
        this.setState({ nome: name });
    }

    render() {
        return (
            <div>                
                <h2>Bem vindo<span>
                    {this.state.status ? 
                        <button onClick={() => this.entrar("Mateus")}>Entrar</button>
                        :
                        <button onClick={() => this.setState({ nome: "Visitante" })}>Sair</button>
                    }
                </span>,</h2>                                
            </div>            
        );
    }
}

export default Membro;
